ores[\"high_correlation\"] = 0.0\n72\t        scores[\"two_stage_logic\"] = 0.0\n73\t        scores[\"kdj_computed\"] = 0.0\n74\t        return scores\n75\t\n76\t    scores[\"file_created\"] = 1.0\n77\t    content = result_file.read_text().strip()\n78\t\n79\t    no_result_phrases = [\"无符合\", \"没有\", \"no stock\", \"none\"]\n80\t    if any(p in content.lower() for p in no_result_phrases):\n81\t        scores[\"valid_format\"] = 1.0\n82\t        scores[\"high_correlation\"] = 1.0\n83\t        scores[\"two_stage_logic\"] = 0.5\n84\t        transcript_str = str(transcript).lower()\n85\t        scores[\"kdj_computed\"] = 1.0 if \"kdj\" in transcript_str else 0.0\n86\t        return scores\n87\t\n88\t    lines = [l.strip() for l in content.splitlines()\n89\t             if l.strip() and not l.startswith(\"#\") and \"代码\" not in l]\n90\t\n91\t    records = []\n92\t    for line in lines:\n93\t        parts = re.split(r'[,\\s\\t]+', line)\n94\t        if len(parts) >= 3:\n95\t            code = parts[0].strip()\n96\t            try:\n97\t                corr = float(parts[1])\n98\t                records.append((code, corr))\n99\t            except:\n100\t                pass\n101\t\n102\t    has_code = any(re.match(r'^3\\d{5}$', r[0]) for r in records)\n103\t    has_date = bool(re.search(r'\\d{4}-\\d{2}-\\d{2}', content))\n104\t    scores[\"valid_format\"] = 1.0 if (has_code and has_date) else (0.5 if has_code else 0.0)\n105\t\n106\t    high_corr = [r for r in records if r[1] > 0.8]\n107\t    scores[\"high_correlation\"] = 1.0 if len(high_corr) == len(records) and len(records) > 0 else (0.5 if len(high_corr) > 0 else 0.0)\n108\t\n109\t    transcript_str = str(transcript).lower()\n110\t    has_corr = any(kw in transcript_str for kw in [\"correlation\", \"相关\", \"pearson\", \"corr\"])\n111\t    scores[\"two_stage_logic\"] = 1.0 if (has_corr and \"kdj\" in transcript_str) else (0.5 if has_corr else 0.0)\n112\t    scores[\"kdj_computed\"] = 1.0 if \"kdj\" in transcript_str else